import{_ as t,o,c as a,a2 as d}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"Multi-Agent Development Model","description":"","frontmatter":{},"headers":[],"relativePath":"multi-agent.md","filePath":"multi-agent.md"}'),s={name:"multi-agent.md"};function n(i,e,r,c,l,h){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="multi-agent-development-model" tabindex="-1">Multi-Agent Development Model <a class="header-anchor" href="#multi-agent-development-model" aria-label="Permalink to &quot;Multi-Agent Development Model&quot;">​</a></h1><p>This project is co-developed by two AI coding agents — <strong>Claude Code</strong> and <strong>Codex</strong> — alongside the human developer. This document records the model we use, the decisions behind it, and the conventions each agent must follow.</p><h2 id="how-we-got-here" tabindex="-1">How we got here <a class="header-anchor" href="#how-we-got-here" aria-label="Permalink to &quot;How we got here&quot;">​</a></h2><p>This model was established in a three-way conversation (developer + Claude Code + Codex) on 2026-06-29. Both agents were consulted simultaneously, proposed a shared structure, and refined it collaboratively before it was written down. The exercise itself validated the model: two agents can work on the same codebase without conflict when the conventions are clear and the human is the scheduler.</p><h2 id="the-model" tabindex="-1">The model <a class="header-anchor" href="#the-model" aria-label="Permalink to &quot;The model&quot;">​</a></h2><p>Each agent works from its own <strong>separate local clone</strong> of the repository. There is no shared working tree, no shared branch, and no shared <code>CURRENT_TASK.md</code>. Agents work independently; the only shared state is <code>main</code> (via git).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Developer</span></span>\n<span class="line"><span>   ├── Clone A  →  Claude Code</span></span>\n<span class="line"><span>   └── Clone B  →  Codex</span></span>\n<span class="line"><span>              ↑</span></span>\n<span class="line"><span>           git remote (shared main)</span></span></code></pre></div><h2 id="task-assignment" tabindex="-1">Task assignment <a class="header-anchor" href="#task-assignment" aria-label="Permalink to &quot;Task assignment&quot;">​</a></h2><p>The <strong>developer assigns tasks explicitly</strong> at the start of each session. Neither agent infers its next task from a file — there is no <code>⏳ Next:</code> pointer in <code>CLAUDE.md</code> or <code>AGENTS.md</code>.</p><p><code>docs/roadmap.md</code> is the canonical task queue. The developer reads it, decides which task each agent picks up, and tells the agent at session start. Open PRs show what is in flight.</p><h2 id="agent-specific-context-files" tabindex="-1">Agent-specific context files <a class="header-anchor" href="#agent-specific-context-files" aria-label="Permalink to &quot;Agent-specific context files&quot;">​</a></h2><p>Each agent has its own context file that acts as a tool-specific adapter:</p><table tabindex="0"><thead><tr><th>File</th><th>Read by</th><th>Purpose</th></tr></thead><tbody><tr><td><code>CLAUDE.md</code></td><td>Claude Code</td><td>Conventions, rules, pointers to <code>docs/</code></td></tr><tr><td><code>AGENTS.md</code></td><td>Codex</td><td>Same structure, Codex-specific mechanics</td></tr></tbody></table><p>These files are <strong>lean, stable adapters</strong> — not changelogs. They contain conventions and architectural rules. They do not contain task completion history.</p><h2 id="shared-source-of-truth" tabindex="-1">Shared source of truth <a class="header-anchor" href="#shared-source-of-truth" aria-label="Permalink to &quot;Shared source of truth&quot;">​</a></h2><p>Both agents read the same <code>docs/</code> tree without modification:</p><ul><li><code>docs/roadmap.md</code> — task queue and completion record (✅ entries go here)</li><li><code>docs/epics/</code> — full task detail</li><li><code>docs/development-workflow.md</code> — branch/PR/commit mechanics</li><li><code>docs/sovereign-proposal-plan-srs.md</code> — architecture and SRS</li><li>Everything else in <code>docs/</code></li></ul><p>Neither agent writes anything to these files that the other would need to undo. Completion is recorded once, in <code>docs/roadmap.md</code>, in the PR that delivers the work.</p><h2 id="commit-trailers" tabindex="-1">Commit trailers <a class="header-anchor" href="#commit-trailers" aria-label="Permalink to &quot;Commit trailers&quot;">​</a></h2><p>Commit trailers identify which agent authored the work:</p><ul><li><strong>Claude Code</strong>: <code>Co-Authored-By: Claude Code &lt;noreply@anthropic.com&gt;</code></li><li><strong>Codex</strong>: <code>Co-Authored-By: Codex &lt;noreply@openai.com&gt;</code> <em>(or whatever value Codex&#39;s local config emits)</em></li></ul><h2 id="what-does-not-go-in-claude-md-or-agents-md" tabindex="-1">What does NOT go in <code>CLAUDE.md</code> or <code>AGENTS.md</code> <a class="header-anchor" href="#what-does-not-go-in-claude-md-or-agents-md" aria-label="Permalink to &quot;What does NOT go in `CLAUDE.md` or `AGENTS.md`&quot;">​</a></h2><ul><li>Task completion entries — use <code>docs/roadmap.md</code></li><li>A &quot;next task&quot; pointer — the developer assigns this at session start</li><li>Git history or recent changes — <code>git log</code> is authoritative</li><li>Debugging solutions — the fix is in the code; the commit message has the context</li></ul><h2 id="decision-log" tabindex="-1">Decision log <a class="header-anchor" href="#decision-log" aria-label="Permalink to &quot;Decision log&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Date</th><th>Decision</th><th>Rationale</th></tr></thead><tbody><tr><td>2026-06-29</td><td>Separate clones per agent, no shared working tree</td><td>Eliminates all coordination overhead; each agent is fully isolated</td></tr><tr><td>2026-06-29</td><td>Drop <code>⏳ Next:</code> pointer from <code>CLAUDE.md</code></td><td>With two agents, a single pointer is ambiguous; the developer is the scheduler</td></tr><tr><td>2026-06-29</td><td>Drop completion history from <code>CLAUDE.md</code> / <code>AGENTS.md</code></td><td>These files are tool adapters, not changelogs; <code>docs/roadmap.md</code> + merged PRs are the record</td></tr><tr><td>2026-06-29</td><td>Agent-specific context files (<code>CLAUDE.md</code> / <code>AGENTS.md</code>), shared <code>docs/</code></td><td>Each agent gets native context in its own format; project state is not duplicated</td></tr><tr><td>2026-06-29</td><td>Codex trailer treated as convention, not confirmed identity</td><td>Codex&#39;s actual commit attribution config may differ; the trailer is a best-effort convention until confirmed</td></tr></tbody></table>',25)])])}const u=t(s,[["render",n]]);export{p as __pageData,u as default};
